#include <bits/stdc++.h>
using namespace std;
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};
TreeNode* insert_node(TreeNode* root, int val) {
    if (!root) {
        return new TreeNode(val);
    }
    if (val < root->val) {
        root->left = insert_node(root->left, val);
    } else if (val > root->val) {
        root->right = insert_node(root->right, val);
    }
    return root;
}
TreeNode* find_min(TreeNode* node) {
    while (node->left) {
        node = node->left;
    }
    return node;
}
TreeNode* delete_node(TreeNode* root, int nodeToDelete) {
    if (!root) {
        return root;
    }
    if (nodeToDelete < root->val) {
        root->left = delete_node(root->left, nodeToDelete);
    } else if (nodeToDelete > root->val) {
        root->right = delete_node(root->right, nodeToDelete);
    } else {
        if (!root->left && !root->right) {
            delete root;
            return NULL;
        } else if (!root->left) {
            TreeNode* temp = root->right;
            delete root;
            return temp;
        } else if (!root->right) {
            TreeNode* temp = root->left;
            delete root;
            return temp;
        } else {
            TreeNode* min_node = find_min(root->right);
            root->val = min_node->val;
            root->right = delete_node(root->right, min_node->val);
        }
    }
    return root;
}
void print_tree(TreeNode* node) {
    if (node) {
        cout << node->val << endl;
        print_tree(node->left);
        print_tree(node->right);
    }
}
