    int n;
    cin >> n;
    TreeNode* root = NULL;
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        root = insert_node(root, val);
    }
    int nodeToDelete;
    cin >> nodeToDelete;
    root = delete_node(root, nodeToDelete);
    print_tree(root);
    return 0;
}
